CREATE OR REPLACE FUNCTION fpa_money_amount (as_memno char, ai_year bigint,ai_month bigint,ai_seq bigint) RETURNS bigint AS $body$
DECLARE

  ldc_amt sc_kep_t_monthly_receive.kep_method_amount%type;

BEGIN
  select sum(sc_kep_t_monthly_receive.kep_method_amount)
  into STRICT ldc_amt
  from sc_kep_t_monthly_receive
  where (membership_no = as_memno)
  and (receive_year = ai_year)
  and (receive_month = ai_month)
  and (seq_no = ai_seq);

  if coalesce(ldc_amt::text, '') = '' then ldc_amt := 0;end if;

  return coalesce(ldc_amt,0);
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
